import 'package:injectable/injectable.dart'; import '../model/capture_config.dart'; import '../model/capture_quality.dart'; @injectable class CaptureQualityManager { CaptureConfig fromQuality(CaptureQuality quality) { switch (quality) { case CaptureQuality.low: return CaptureConfig.low; case CaptureQuality.high: return CaptureConfig.high; case CaptureQuality.ultra: return const CaptureConfig(fps: 30, bitrateKbps: 8000, width: 1920, height: 1080); default: return const CaptureConfig(); } } CaptureQuality qualityFromConfig(CaptureConfig config) { if (config.fps >= 30 && config.bitrateKbps >= 4000) return CaptureQuality.high; if (config.fps <= 10) return CaptureQuality.low; return CaptureQuality.medium; } }